#!/usr/bin/env node
import { Command } from 'commander';
import robot from '@jitsi/robotjs';

export const MIN_INTERVAL_MS = 1000;
export const MAX_PIXELS = 20;
export const MIN_THRESHOLD_MS = 5000;
export const VALID_MODES = ['mouse', 'keyboard', 'both'] as const;

export type Mode = (typeof VALID_MODES)[number];

export interface Config {
  intervalMs: number;
  movementPx: number;
  idleThresholdMs: number;
  mode: Mode;
  verbose: boolean;
}

export interface ValidationResult {
  valid: boolean;
  error?: string;
}

export function validateInterval(value: number): ValidationResult {
  if (isNaN(value) || value < MIN_INTERVAL_MS) {
    return { valid: false, error: `Interval must be >= ${MIN_INTERVAL_MS}ms` };
  }
  return { valid: true };
}

export function validatePixels(value: number): ValidationResult {
  if (isNaN(value) || value < 1 || value > MAX_PIXELS) {
    return { valid: false, error: `Pixels must be between 1 and ${MAX_PIXELS}` };
  }
  return { valid: true };
}

export function validateThreshold(value: number): ValidationResult {
  if (isNaN(value) || value < MIN_THRESHOLD_MS) {
    return { valid: false, error: `Threshold must be >= ${MIN_THRESHOLD_MS}ms` };
  }
  return { valid: true };
}

export function validateMode(value: string): ValidationResult {
  if (!VALID_MODES.includes(value as Mode)) {
    return {
      valid: false,
      error: `Invalid mode "${value}". Valid options: ${VALID_MODES.join(', ')}`,
    };
  }
  return { valid: true };
}

export function getRandomInterval(baseMs: number, variancePercent = 0.3): number {
  const variance = baseMs * variancePercent;
  return Math.round(baseMs + (Math.random() * 2 - 1) * variance);
}

export class Compliance {
  private intervalId: NodeJS.Timeout | null = null;
  private lastPos: { x: number; y: number } | null = null;
  private lastActivityTime: number = Date.now();

  constructor(private config: Config) {}

  start(): void {
    this.log('Starting Compliance...');
    this.log(`Config: interval=${this.config.intervalMs}ms, mode=${this.config.mode}`);

    this.scheduleNext();

    process.on('SIGINT', () => this.shutdown());
    process.on('SIGTERM', () => this.shutdown());
  }

  private scheduleNext(): void {
    const interval = getRandomInterval(this.config.intervalMs);
    this.log(`Next tick in ${interval}ms`);
    this.intervalId = setTimeout(() => {
      this.tick();
      this.scheduleNext();
    }, interval);
  }

  private tick(): void {
    if (!this.shouldActivate()) {
      this.log('User active, skipping...');
      return;
    }

    switch (this.config.mode) {
      case 'mouse':
        this.jiggleMouse();
        break;
      case 'keyboard':
        this.jiggleKeyboard();
        break;
      case 'both':
        Math.random() > 0.5 ? this.jiggleMouse() : this.jiggleKeyboard();
        break;
    }
  }

  private jiggleMouse(): void {
    try {
      const { x, y } = robot.getMousePos();
      const angle = Math.random() * Math.PI * 2;
      const radius = this.config.movementPx;

      const newX = Math.round(x + Math.cos(angle) * radius);
      const newY = Math.round(y + Math.sin(angle) * radius);

      robot.moveMouse(newX, newY);

      setTimeout(() => {
        robot.moveMouse(x, y);
      }, 30 + Math.random() * 50);

      this.log(`Mouse jiggle: (${x},${y}) → (${newX},${newY}) → (${x},${y})`);
    } catch (err) {
      console.error('[ERROR] Mouse jiggle failed:', err);
      console.error('[ERROR] Make sure Accessibility permission is granted');
    }
  }

  private jiggleKeyboard(): void {
    try {
      robot.keyToggle('shift', 'down');
      robot.keyToggle('shift', 'up');
      this.log('Keyboard jiggle: Shift press/release');
    } catch (err) {
      console.error('[ERROR] Keyboard jiggle failed:', err);
    }
  }

  private shouldActivate(): boolean {
    const currentPos = robot.getMousePos();

    if (
      this.lastPos &&
      (currentPos.x !== this.lastPos.x || currentPos.y !== this.lastPos.y)
    ) {
      this.lastActivityTime = Date.now();
    }

    this.lastPos = currentPos;

    const idleTime = Date.now() - this.lastActivityTime;
    return idleTime > this.config.idleThresholdMs;
  }

  private log(message: string): void {
    if (this.config.verbose) {
      const timestamp = new Date().toISOString();
      console.log(`[${timestamp}] ${message}`);
    }
  }

  private shutdown(): void {
    this.log('Shutting down...');
    if (this.intervalId) {
      clearTimeout(this.intervalId);
    }
    process.exit(0);
  }
}

function main(): void {
  const program = new Command();

  program
    .name('compliance')
    .description('Keep MS Teams status always Available by simulating activity')
    .version('1.0.0')
    .option('-i, --interval <ms>', 'Interval between activities (ms)', '60000')
    .option('-p, --pixels <px>', 'Mouse movement distance (pixels)', '2')
    .option('-t, --threshold <ms>', 'Idle threshold before activating (ms)', '30000')
    .option('-m, --mode <mode>', 'Activity mode: mouse, keyboard, both', 'mouse')
    .option('-v, --verbose', 'Enable verbose logging', false)
    .action((options) => {
      const intervalMs = parseInt(options.interval, 10);
      const movementPx = parseInt(options.pixels, 10);
      const idleThresholdMs = parseInt(options.threshold, 10);

      const intervalValidation = validateInterval(intervalMs);
      if (!intervalValidation.valid) {
        console.error(`Error: ${intervalValidation.error}`);
        process.exit(1);
      }

      const pixelsValidation = validatePixels(movementPx);
      if (!pixelsValidation.valid) {
        console.error(`Error: ${pixelsValidation.error}`);
        process.exit(1);
      }

      const thresholdValidation = validateThreshold(idleThresholdMs);
      if (!thresholdValidation.valid) {
        console.error(`Error: ${thresholdValidation.error}`);
        process.exit(1);
      }

      const modeValidation = validateMode(options.mode);
      if (!modeValidation.valid) {
        console.error(`Error: ${modeValidation.error}`);
        process.exit(1);
      }

      const config: Config = {
        intervalMs,
        movementPx,
        idleThresholdMs,
        mode: options.mode as Mode,
        verbose: options.verbose,
      };

      console.log('');
      console.log('╔════════════════════════════════════════╗');
      console.log('║         Compliance v1.0.0              ║');
      console.log('╚════════════════════════════════════════╝');
      console.log('');
      console.log('Press Ctrl+C to stop');
      console.log('');

      const keeper = new Compliance(config);
      keeper.start();
    });

  program.parse();
}

const isMainModule =
  typeof require !== 'undefined' && require.main === module;
const isDirectRun =
  typeof import.meta !== 'undefined' &&
  import.meta.url === `file://${process.argv[1]}`;

if (isMainModule || isDirectRun) {
  main();
}

