import { describe, it, expect } from 'vitest';
import {
  validateInterval,
  validatePixels,
  validateThreshold,
  validateMode,
  getRandomInterval,
  MIN_INTERVAL_MS,
  MAX_PIXELS,
  MIN_THRESHOLD_MS,
  VALID_MODES,
} from '../index.js';

describe('validateInterval', () => {
  it('should accept valid intervals', () => {
    expect(validateInterval(1000)).toEqual({ valid: true });
    expect(validateInterval(60000)).toEqual({ valid: true });
    expect(validateInterval(300000)).toEqual({ valid: true });
  });

  it('should reject intervals below minimum', () => {
    const result = validateInterval(500);
    expect(result.valid).toBe(false);
    expect(result.error).toContain(`>= ${MIN_INTERVAL_MS}`);
  });

  it('should reject NaN values', () => {
    const result = validateInterval(NaN);
    expect(result.valid).toBe(false);
  });

  it('should reject zero', () => {
    const result = validateInterval(0);
    expect(result.valid).toBe(false);
  });

  it('should reject negative values', () => {
    const result = validateInterval(-1000);
    expect(result.valid).toBe(false);
  });
});

describe('validatePixels', () => {
  it('should accept valid pixel values', () => {
    expect(validatePixels(1)).toEqual({ valid: true });
    expect(validatePixels(2)).toEqual({ valid: true });
    expect(validatePixels(10)).toEqual({ valid: true });
    expect(validatePixels(MAX_PIXELS)).toEqual({ valid: true });
  });

  it('should reject zero', () => {
    const result = validatePixels(0);
    expect(result.valid).toBe(false);
    expect(result.error).toContain('between 1 and');
  });

  it('should reject values above maximum', () => {
    const result = validatePixels(MAX_PIXELS + 1);
    expect(result.valid).toBe(false);
  });

  it('should reject negative values', () => {
    const result = validatePixels(-5);
    expect(result.valid).toBe(false);
  });

  it('should reject NaN values', () => {
    const result = validatePixels(NaN);
    expect(result.valid).toBe(false);
  });
});

describe('validateThreshold', () => {
  it('should accept valid threshold values', () => {
    expect(validateThreshold(5000)).toEqual({ valid: true });
    expect(validateThreshold(30000)).toEqual({ valid: true });
    expect(validateThreshold(60000)).toEqual({ valid: true });
  });

  it('should reject thresholds below minimum', () => {
    const result = validateThreshold(1000);
    expect(result.valid).toBe(false);
    expect(result.error).toContain(`>= ${MIN_THRESHOLD_MS}`);
  });

  it('should reject zero', () => {
    const result = validateThreshold(0);
    expect(result.valid).toBe(false);
  });

  it('should reject negative values', () => {
    const result = validateThreshold(-5000);
    expect(result.valid).toBe(false);
  });

  it('should reject NaN values', () => {
    const result = validateThreshold(NaN);
    expect(result.valid).toBe(false);
  });
});

describe('validateMode', () => {
  it('should accept all valid modes', () => {
    for (const mode of VALID_MODES) {
      expect(validateMode(mode)).toEqual({ valid: true });
    }
  });

  it('should reject invalid modes', () => {
    const result = validateMode('invalid');
    expect(result.valid).toBe(false);
    expect(result.error).toContain('Invalid mode');
    expect(result.error).toContain(VALID_MODES.join(', '));
  });

  it('should reject empty string', () => {
    const result = validateMode('');
    expect(result.valid).toBe(false);
  });

  it('should be case-sensitive', () => {
    const result = validateMode('MOUSE');
    expect(result.valid).toBe(false);
  });
});

describe('getRandomInterval', () => {
  it('should return values within ±30% variance', () => {
    const baseMs = 60000;
    const variance = 0.3;
    const minExpected = Math.round(baseMs * (1 - variance));
    const maxExpected = Math.round(baseMs * (1 + variance));

    for (let i = 0; i < 100; i++) {
      const result = getRandomInterval(baseMs);
      expect(result).toBeGreaterThanOrEqual(minExpected);
      expect(result).toBeLessThanOrEqual(maxExpected);
    }
  });

  it('should return integer values', () => {
    for (let i = 0; i < 50; i++) {
      const result = getRandomInterval(60000);
      expect(Number.isInteger(result)).toBe(true);
    }
  });

  it('should accept custom variance percentage', () => {
    const baseMs = 10000;
    const customVariance = 0.1;
    const minExpected = Math.round(baseMs * (1 - customVariance));
    const maxExpected = Math.round(baseMs * (1 + customVariance));

    for (let i = 0; i < 100; i++) {
      const result = getRandomInterval(baseMs, customVariance);
      expect(result).toBeGreaterThanOrEqual(minExpected);
      expect(result).toBeLessThanOrEqual(maxExpected);
    }
  });

  it('should produce varying results (not always the same)', () => {
    const results = new Set<number>();
    for (let i = 0; i < 20; i++) {
      results.add(getRandomInterval(60000));
    }
    expect(results.size).toBeGreaterThan(1);
  });
});

describe('constants', () => {
  it('should have sensible default values', () => {
    expect(MIN_INTERVAL_MS).toBe(1000);
    expect(MAX_PIXELS).toBe(20);
    expect(MIN_THRESHOLD_MS).toBe(5000);
    expect(VALID_MODES).toEqual(['mouse', 'keyboard', 'both']);
  });
});

