import {
  Config,
  DEFAULT_CONFIG,
  ValidationResult,
  MIN_INTERVAL_MS,
  MAX_PIXELS,
  MIN_THRESHOLD_MS,
  VALID_MODES,
  Mode,
} from './types.js';

export function loadConfig(): Config {
  ensureConfigDir();

  if (!existsSync(CONFIG_FILE)) {
    return { ...DEFAULT_CONFIG };
  }

  try {
    const content = readFileSync(CONFIG_FILE, 'utf-8');
    const parsed = JSON.parse(content) as Partial<Config>;
    return { ...DEFAULT_CONFIG, ...parsed };
  } catch {
    return { ...DEFAULT_CONFIG };
  }
}

export function saveConfig(config: Config): void {
  ensureConfigDir();
  writeFileSync(CONFIG_FILE, JSON.stringify(config, null, 2), 'utf-8');
}

export function getConfigValue<K extends keyof Config>(key: K): Config[K] {
  const config = loadConfig();
  return config[key];
}

export function setConfigValue<K extends keyof Config>(
  key: K,
  value: Config[K]
): ValidationResult {
  const validation = validateConfigValue(key, value);
  if (!validation.valid) {
    return validation;
  }

  const config = loadConfig();
  config[key] = value;
  saveConfig(config);
  return { valid: true };
}

export function resetConfig(): void {
  saveConfig({ ...DEFAULT_CONFIG });
}

export function getDefaults(): Config {
  return { ...DEFAULT_CONFIG };
}

export function validateInterval(value: number): ValidationResult {
  if (isNaN(value) || value < MIN_INTERVAL_MS) {
    return { valid: false, error: `Interval must be >= ${MIN_INTERVAL_MS}ms` };
  }
  return { valid: true };
}

export function validatePixels(value: number): ValidationResult {
  if (isNaN(value) || value < 1 || value > MAX_PIXELS) {
    return { valid: false, error: `Pixels must be between 1 and ${MAX_PIXELS}` };
  }
  return { valid: true };
}

export function validateThreshold(value: number): ValidationResult {
  if (isNaN(value) || value < MIN_THRESHOLD_MS) {
    return { valid: false, error: `Threshold must be >= ${MIN_THRESHOLD_MS}ms` };
  }
  return { valid: true };
}

export function validateMode(value: string): ValidationResult {
  if (!VALID_MODES.includes(value as Mode)) {
    return {
      valid: false,
      error: `Invalid mode "${value}". Valid options: ${VALID_MODES.join(', ')}`,
    };
  }
  return { valid: true };
}

export function validateConfigValue<K extends keyof Config>(
  key: K,
  value: Config[K]
): ValidationResult {
  switch (key) {
    case 'intervalMs':
      return validateInterval(value as number);
    case 'movementPx':
      return validatePixels(value as number);
    case 'idleThresholdMs':
      return validateThreshold(value as number);
    case 'mode':
      return validateMode(value as string);
    case 'verbose':
      if (typeof value !== 'boolean') {
        return { valid: false, error: 'Verbose must be true or false' };
      }
      return { valid: true };
    default:
      return { valid: false, error: `Unknown config key: ${key}` };
  }
}

export function parseConfigValue(
  key: keyof Config,
  value: string
): { parsed: Config[keyof Config]; error?: string } {
  switch (key) {
    case 'intervalMs':
    case 'movementPx':
    case 'idleThresholdMs': {
      const num = parseInt(value, 10);
      if (isNaN(num)) {
        return { parsed: 0, error: `Invalid number: ${value}` };
      }
      return { parsed: num };
    }
    case 'mode':
      return { parsed: value as Mode };
    case 'verbose':
      if (value === 'true' || value === '1') return { parsed: true };
      if (value === 'false' || value === '0') return { parsed: false };
      return { parsed: false, error: 'Verbose must be true or false' };
    default:
      return { parsed: value, error: `Unknown key: ${key}` };
  }
}

export function formatConfig(config: Config): string {
  const lines = [
    '┌─────────────────────────────────────┐',
    '│         Current Configuration       │',
    '├─────────────────────────────────────┤',
    `│  intervalMs      │ ${String(config.intervalMs).padEnd(16)} │`,
    `│  movementPx      │ ${String(config.movementPx).padEnd(16)} │`,
    `│  idleThresholdMs │ ${String(config.idleThresholdMs).padEnd(16)} │`,
    `│  mode            │ ${config.mode.padEnd(16)} │`,
    `│  verbose         │ ${String(config.verbose).padEnd(16)} │`,
    '└─────────────────────────────────────┘',
  ];
  return lines.join('\n');
}

