import { STATS_FILE, ensureConfigDir } from './paths.js';
import { Stats, EMPTY_STATS } from './types.js';

export function loadStats(): Stats {
  ensureConfigDir();

  if (!existsSync(STATS_FILE)) {
    return { ...EMPTY_STATS };
  }

  try {
    const content = readFileSync(STATS_FILE, 'utf-8');
    const parsed = JSON.parse(content) as Partial<Stats>;
    return { ...EMPTY_STATS, ...parsed };
  } catch {
    return { ...EMPTY_STATS };
  }
}

export function saveStats(stats: Stats): void {
  ensureConfigDir();
  writeFileSync(STATS_FILE, JSON.stringify(stats, null, 2), 'utf-8');
}

export function incrementJiggle(type: 'mouse' | 'keyboard'): void {
  const stats = loadStats();
  stats.totalJiggles++;
  stats.lastJiggleAt = new Date().toISOString();

  if (type === 'mouse') {
    stats.mouseJiggles++;
  } else {
    stats.keyboardJiggles++;
  }

  saveStats(stats);
}

export function incrementSkipped(): void {
  const stats = loadStats();
  stats.skippedDueToActivity++;
  saveStats(stats);
}

export function markStarted(): void {
  const stats = loadStats();
  stats.startedAt = new Date().toISOString();
  saveStats(stats);
}

export function resetStats(): void {
  saveStats({ ...EMPTY_STATS });
}

export function formatDuration(ms: number): string {
  const seconds = Math.floor(ms / 1000);
  const minutes = Math.floor(seconds / 60);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);

  if (days > 0) {
    return `${days}d ${hours % 24}h ${minutes % 60}m`;
  }
  if (hours > 0) {
    return `${hours}h ${minutes % 60}m ${seconds % 60}s`;
  }
  if (minutes > 0) {
    return `${minutes}m ${seconds % 60}s`;
  }
  return `${seconds}s`;
}

export function formatStats(stats: Stats): string {
  let uptime = 'Not running';
  if (stats.startedAt) {
    const startDate = new Date(stats.startedAt);
    const now = new Date();
    uptime = formatDuration(now.getTime() - startDate.getTime());
  }

  let lastJiggle = 'Never';
  if (stats.lastJiggleAt) {
    const lastDate = new Date(stats.lastJiggleAt);
    const now = new Date();
    const ago = formatDuration(now.getTime() - lastDate.getTime());
    lastJiggle = `${ago} ago`;
  }

  const lines = [
    '┌─────────────────────────────────────┐',
    '│            Statistics               │',
    '├─────────────────────────────────────┤',
    `│  Uptime          │ ${uptime.padEnd(16)} │`,
    `│  Total jiggles   │ ${String(stats.totalJiggles).padEnd(16)} │`,
    `│  Mouse jiggles   │ ${String(stats.mouseJiggles).padEnd(16)} │`,
    `│  Keyboard jiggles│ ${String(stats.keyboardJiggles).padEnd(16)} │`,
    `│  Skipped (active)│ ${String(stats.skippedDueToActivity).padEnd(16)} │`,
    `│  Last jiggle     │ ${lastJiggle.padEnd(16)} │`,
    '└─────────────────────────────────────┘',
  ];
  return lines.join('\n');
}

