import { describe, it, expect } from 'vitest';
import { getRandomInterval } from '../src/daemon.js';

describe('getRandomInterval', () => {
  it('should return values within ±30% variance', () => {
    const baseMs = 60000;
    const variance = 0.3;
    const minExpected = Math.round(baseMs * (1 - variance));
    const maxExpected = Math.round(baseMs * (1 + variance));

    for (let i = 0; i < 100; i++) {
      const result = getRandomInterval(baseMs);
      expect(result).toBeGreaterThanOrEqual(minExpected);
      expect(result).toBeLessThanOrEqual(maxExpected);
    }
  });

  it('should return integer values', () => {
    for (let i = 0; i < 50; i++) {
      const result = getRandomInterval(60000);
      expect(Number.isInteger(result)).toBe(true);
    }
  });

  it('should accept custom variance percentage', () => {
    const baseMs = 10000;
    const customVariance = 0.1;
    const minExpected = Math.round(baseMs * (1 - customVariance));
    const maxExpected = Math.round(baseMs * (1 + customVariance));

    for (let i = 0; i < 100; i++) {
      const result = getRandomInterval(baseMs, customVariance);
      expect(result).toBeGreaterThanOrEqual(minExpected);
      expect(result).toBeLessThanOrEqual(maxExpected);
    }
  });

  it('should produce varying results (not always the same)', () => {
    const results = new Set<number>();
    for (let i = 0; i < 20; i++) {
      results.add(getRandomInterval(60000));
    }
    expect(results.size).toBeGreaterThan(1);
  });
});

