#!/usr/bin/env node
import { Command } from 'commander';
import { spawn, execSync } from 'node:child_process';
import { existsSync, readFileSync, openSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';

import { Config, Mode } from './types.js';
import {
  loadConfig,
  saveConfig,
  resetConfig,
  formatConfig,
  parseConfigValue,
  setConfigValue,
  validateInterval,
  validatePixels,
  validateThreshold,
  validateMode,
} from './config.js';
import { loadStats, formatStats, resetStats } from './stats.js';
import {
  ComplianceDaemon,
  isDaemonRunning,
  readPidFile,
  removePidFile,
  getLogFile,
} from './daemon.js';
import { LOG_FILE, CONFIG_DIR } from './paths.js';

const VERSION = '1.1.0';

function startCommand(options: {
  interval?: string;
  pixels?: string;
  threshold?: string;
  mode?: string;
  verbose?: boolean;
  daemon?: boolean;
}): void {
  const { running, pid } = isDaemonRunning();
  if (running) {
    console.log(`Compliance is already running (PID: ${pid})`);
    console.log('Use "compliance stop" to stop it first.');
    process.exit(1);
  }

  const config = loadConfig();

  if (options.interval) {
    const val = parseInt(options.interval, 10);
    const validation = validateInterval(val);
    if (!validation.valid) {
      console.error(`Error: ${validation.error}`);
      process.exit(1);
    }
    config.intervalMs = val;
  }

  if (options.pixels) {
    const val = parseInt(options.pixels, 10);
    const validation = validatePixels(val);
    if (!validation.valid) {
      console.error(`Error: ${validation.error}`);
      process.exit(1);
    }
    config.movementPx = val;
  }

  if (options.threshold) {
    const val = parseInt(options.threshold, 10);
    const validation = validateThreshold(val);
    if (!validation.valid) {
      console.error(`Error: ${validation.error}`);
      process.exit(1);
    }
    config.idleThresholdMs = val;
  }

  if (options.mode) {
    const validation = validateMode(options.mode);
    if (!validation.valid) {
      console.error(`Error: ${validation.error}`);
      process.exit(1);
    }
    config.mode = options.mode as Mode;
  }

  if (options.verbose !== undefined) {
    config.verbose = options.verbose;
  }

  if (options.daemon) {
    const __filename = fileURLToPath(import.meta.url);
    const scriptPath = __filename;

    const args = ['start'];
    if (config.verbose) args.push('-v');
    args.push('-i', String(config.intervalMs));
    args.push('-p', String(config.movementPx));
    args.push('-t', String(config.idleThresholdMs));
    args.push('-m', config.mode);

    const logFd = require('fs').openSync(LOG_FILE, 'a');

    const child = spawn('node', [scriptPath, ...args], {
      detached: true,
      stdio: ['ignore', logFd, logFd],
    });

    child.unref();

    console.log('');
    console.log('╔════════════════════════════════════════╗');
    console.log('║    Compliance Daemon Started           ║');
    console.log('╚════════════════════════════════════════╝');
    console.log('');
    console.log(`  PID: ${child.pid}`);
    console.log(`  Log: ${LOG_FILE}`);
    console.log('');
    console.log('Commands:');
    console.log('  compliance status  - Check status');
    console.log('  compliance logs    - View logs');
    console.log('  compliance stop    - Stop daemon');
    console.log('');
    process.exit(0);
  }

  console.log('');
  console.log('╔════════════════════════════════════════╗');
  console.log(`║    Compliance v${VERSION}                   ║`);
  console.log('╚════════════════════════════════════════╝');
  console.log('');
  console.log('Press Ctrl+C to stop');
  console.log('');

  const daemon = new ComplianceDaemon(config);
  daemon.start();
}

function stopCommand(): void {
  const { running, pid } = isDaemonRunning();

  if (!running || pid === null) {
    console.log('Compliance is not running.');
    return;
  }

  console.log(`Stopping compliance (PID: ${pid})...`);

  try {
    process.kill(pid, 'SIGTERM');

    let attempts = 0;
    const maxAttempts = 10;

    const checkStopped = setInterval(() => {
      attempts++;
      const { running: stillRunning } = isDaemonRunning();

      if (!stillRunning) {
        clearInterval(checkStopped);
        console.log('Compliance stopped.');
        removePidFile();
        process.exit(0);
      }

      if (attempts >= maxAttempts) {
        clearInterval(checkStopped);
        console.log('Force killing...');
        try {
          process.kill(pid, 'SIGKILL');
        } catch {
          // Process may already be dead
        }
        removePidFile();
        console.log('Compliance stopped.');
        process.exit(0);
      }
    }, 500);
  } catch (err) {
    console.error('Failed to stop compliance:', err);
    removePidFile();
    process.exit(1);
  }
}

function statusCommand(): void {
  const { running, pid } = isDaemonRunning();

  console.log('');
  if (running && pid) {
    console.log(`Status: ✅ Running (PID: ${pid})`);
  } else {
    console.log('Status: ⏹  Not running');
  }
  console.log('');

  const stats = loadStats();
  console.log(formatStats(stats));
  console.log('');

  const config = loadConfig();
  console.log(formatConfig(config));
  console.log('');

  console.log(`Config directory: ${CONFIG_DIR}`);
  console.log(`Log file: ${LOG_FILE}`);
  console.log('');
}

function configCommand(
  action?: string,
  key?: string,
  value?: string
): void {
  if (!action) {
    const config = loadConfig();
    console.log('');
    console.log(formatConfig(config));
    console.log('');
    console.log(`Config file: ${CONFIG_DIR}/config.json`);
    console.log('');
    console.log('Usage:');
    console.log('  compliance config set <key> <value>  - Set a value');
    console.log('  compliance config get <key>          - Get a value');
    console.log('  compliance config reset              - Reset to defaults');
    console.log('');
    console.log('Keys: intervalMs, movementPx, idleThresholdMs, mode, verbose');
    console.log('');
    return;
  }

  if (action === 'reset') {
    resetConfig();
    resetStats();
    console.log('Configuration and stats reset to defaults.');
    return;
  }

  if (action === 'get') {
    if (!key) {
      console.error('Usage: compliance config get <key>');
      process.exit(1);
    }
    const config = loadConfig();
    const validKeys = Object.keys(config);
    if (!validKeys.includes(key)) {
      console.error(`Unknown key: ${key}`);
      console.error(`Valid keys: ${validKeys.join(', ')}`);
      process.exit(1);
    }
    console.log(`${key}: ${config[key as keyof Config]}`);
    return;
  }

  if (action === 'set') {
    if (!key || !value) {
      console.error('Usage: compliance config set <key> <value>');
      process.exit(1);
    }

    const config = loadConfig();
    const validKeys = Object.keys(config);
    if (!validKeys.includes(key)) {
      console.error(`Unknown key: ${key}`);
      console.error(`Valid keys: ${validKeys.join(', ')}`);
      process.exit(1);
    }

    const { parsed, error } = parseConfigValue(key as keyof Config, value);
    if (error || parsed === null) {
      console.error(`Error: ${error || 'Invalid value'}`);
      process.exit(1);
    }

    const result = setConfigValue(key as keyof Config, parsed);
    if (!result.valid) {
      console.error(`Error: ${result.error}`);
      process.exit(1);
    }

    console.log(`Set ${key} = ${parsed}`);
    return;
  }

  console.error(`Unknown action: ${action}`);
  console.error('Valid actions: set, get, reset');
  process.exit(1);
}

function logsCommand(options: { lines?: string; follow?: boolean }): void {
  const logFile = getLogFile();

  if (!existsSync(logFile)) {
    console.log('No log file found. Start the daemon first.');
    return;
  }

  const lines = parseInt(options.lines || '50', 10);

  if (options.follow) {
    console.log(`Following ${logFile}... (Ctrl+C to stop)`);
    const tail = spawn('tail', ['-f', '-n', String(lines), logFile], {
      stdio: 'inherit',
    });
    tail.on('close', () => process.exit(0));
  } else {
    try {
      const content = execSync(`tail -n ${lines} "${logFile}"`, {
        encoding: 'utf-8',
      });
      console.log(content);
    } catch {
      console.log('Unable to read log file.');
    }
  }
}

const program = new Command();

program
  .name('compliance')
  .description('Keep MS Teams status always Available by simulating activity')
  .version(VERSION);

program
  .command('start')
  .description('Start the compliance daemon')
  .option('-i, --interval <ms>', 'Interval between activities (ms)')
  .option('-p, --pixels <px>', 'Mouse movement distance (pixels)')
  .option('-t, --threshold <ms>', 'Idle threshold before activating (ms)')
  .option('-m, --mode <mode>', 'Activity mode: mouse, keyboard, both')
  .option('-v, --verbose', 'Enable verbose logging')
  .option('-d, --daemon', 'Run as background daemon')
  .action(startCommand);

program
  .command('stop')
  .description('Stop the running daemon')
  .action(stopCommand);

program
  .command('status')
  .description('Show daemon status and statistics')
  .action(statusCommand);

program
  .command('config [action] [key] [value]')
  .description('Manage configuration (set/get/reset)')
  .action(configCommand);

program
  .command('logs')
  .description('View log file')
  .option('-n, --lines <n>', 'Number of lines to show', '50')
  .option('-f, --follow', 'Follow log output')
  .action(logsCommand);

program.parse();

