import { execSync } from "node:child_process";
import {
	chmodSync,
	existsSync,
	mkdirSync,
	unlinkSync,
	writeFileSync,
} from "node:fs";
import { homedir } from "node:os";
import { dirname, join, resolve } from "node:path";
import { fileURLToPath } from "node:url";
import { loadConfig } from "./config.js";
import { CONFIG_DIR } from "./paths.js";

const PLIST_NAME = "com.user.compliance";
const LAUNCH_AGENTS_DIR = join(homedir(), "Library", "LaunchAgents");
const PLIST_PATH = join(LAUNCH_AGENTS_DIR, `${PLIST_NAME}.plist`);
const WRAPPER_PATH = join(CONFIG_DIR, "Compliance");

export interface AutostartStatus {
	enabled: boolean;
	loaded: boolean;
	plistPath: string;
}

function getCliPath(): string {
	const __filename = fileURLToPath(import.meta.url);
	const __dirname = dirname(__filename);
	return resolve(__dirname, "cli.js");
}

function getNodePath(): string {
	try {
		return execSync("which node", { encoding: "utf-8" }).trim();
	} catch {
		return "/usr/local/bin/node";
	}
}

function isLaunchAgentLoaded(): boolean {
	try {
		const output = execSync("launchctl list", { encoding: "utf-8" });
		return output.includes(PLIST_NAME);
	} catch {
		return false;
	}
}

export function getAutostartStatus(): AutostartStatus {
	return {
		enabled: existsSync(PLIST_PATH),
		loaded: isLaunchAgentLoaded(),
		plistPath: PLIST_PATH,
	};
}

export function isAutostartEnabled(): boolean {
	return existsSync(PLIST_PATH);
}

function createWrapperScript(): void {
	const cliPath = getCliPath();
	const nodePath = getNodePath();
	const config = loadConfig();

	const args = ["start"];
	if (config.verbose) args.push("-v");
	args.push("-i", String(config.intervalMs));
	args.push("-p", String(config.movementPx));
	args.push("-t", String(config.idleThresholdMs));
	args.push("-m", config.mode);

	const script = `#!/bin/bash
exec "${nodePath}" "${cliPath}" ${args.map((a) => `"${a}"`).join(" ")}
`;

	writeFileSync(WRAPPER_PATH, script, "utf-8");
	chmodSync(WRAPPER_PATH, 0o755);
}

function generatePlist(): string {
	const programArgs = [`        <string>${WRAPPER_PATH}</string>`].join("\n");

	return `<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
    <key>Label</key>
    <string>${PLIST_NAME}</string>
    <key>ProgramArguments</key>
    <array>
${programArgs}
    </array>
    <key>RunAtLoad</key>
    <true/>
    <key>KeepAlive</key>
    <true/>
    <key>StandardOutPath</key>
    <string>/tmp/compliance.launchd.log</string>
    <key>StandardErrorPath</key>
    <string>/tmp/compliance.launchd.error.log</string>
    <key>ThrottleInterval</key>
    <integer>30</integer>
</dict>
</plist>`;
}

export function enableAutostart(): { success: boolean; error?: string } {
	try {
		if (!existsSync(LAUNCH_AGENTS_DIR)) {
			mkdirSync(LAUNCH_AGENTS_DIR, { recursive: true });
		}

		const plistContent = generatePlist();
		writeFileSync(PLIST_PATH, plistContent, "utf-8");

		try {
			execSync(`launchctl unload "${PLIST_PATH}" 2>/dev/null`, {
				encoding: "utf-8",
			});
		} catch {
			// Ignore if not loaded
		}

		execSync(`launchctl load "${PLIST_PATH}"`, { encoding: "utf-8" });

		return { success: true };
	} catch (err) {
		return {
			success: false,
			error: err instanceof Error ? err.message : String(err),
		};
	}
}

export function disableAutostart(): { success: boolean; error?: string } {
	try {
		if (isLaunchAgentLoaded()) {
			try {
				execSync(`launchctl unload "${PLIST_PATH}"`, { encoding: "utf-8" });
			} catch {
				// Ignore unload errors
			}
		}

		if (existsSync(PLIST_PATH)) {
			unlinkSync(PLIST_PATH);
		}

		return { success: true };
	} catch (err) {
		return {
			success: false,
			error: err instanceof Error ? err.message : String(err),
		};
	}
}

export function formatAutostartStatus(): string {
	const status = getAutostartStatus();

	if (status.enabled && status.loaded) {
		return "Autostart: ✅ Enabled (loaded)";
	}
	if (status.enabled && !status.loaded) {
		return "Autostart: ⚠️  Enabled (not loaded - will start on next login)";
	}
	return "Autostart: ⏹  Disabled";
}

